def safe_to_int(val):
    if val is None:
        return 0
    try:
        return int(val)
    except (ValueError, TypeError):
        return 0

print(safe_to_int('42'))
print(safe_to_int('invalid'))
print(safe_to_int(None))

hard.solution:
def format_payload(item):
    if item is None:
        return 'UNKNOWN'
    if isinstance(item, (int, float)):
        return f'${float(item):.2f}'
    if isinstance(item, str):
        return item.upper()
    if isinstance(item, list):
        return ', '.join(map(str, item))
    return 'UNKNOWN'

print(format_payload(50))
print(format_payload('python'))
print(format_payload([10, 20, 30]))
print(format_payload(None))
